  1→import type { StorybookConfig } from '@storybook/react-native-web-vite';
  2→import type { PluginOption } from 'vite';
  3→import { transformWithEsbuild } from 'vite';
  4→import path from 'path';
  5→
  6→const JSX_JS_PACKAGES = [
  7→  'react-native-flip-card',
  8→  '@semparar/design-system-app',
  9→];
 10→
 11→function jsxInJsPlugin(): PluginOption {
 12→  return {
 13→    name: 'storybook:jsx-in-js',
 14→    enforce: 'pre',
 15→    async transform(code, id) {
 16→      const cleanId = id.replace(/\?.*$/, '');
 17→      if (
 18→        /\.js$/.test(cleanId) &&
 19→        JSX_JS_PACKAGES.some(pkg => id.includes(pkg)) &&
 20→        (code.includes('<') || code.includes('/>'))
 21→      ) {
 22→        return transformWithEsbuild(code, id, {
 23→          loader: 'jsx',
 24→          jsx: 'automatic',
 25→        });
 26→      }
 27→    },
 28→  };
 29→}
 30→
 31→const CJS_IN_ESM_PACKAGES = [
 32→  'react-native-svg/lib/module/',
 33→  'react-native-reanimated/lib/module/',
 34→];
 35→
 36→function dtsStubPlugin(): PluginOption {
 37→  return {
 38→    name: 'storybook:dts-stub',
 39→    enforce: 'pre',
 40→    resolveId(source, importer) {
 41→      if (!importer?.includes('@semparar/')) return;
 42→      const cleanImporter = importer.replace(/\?.*$/, '');
 43→      const cleanSource = source.replace(/\?.*$/, '');
 44→      if (cleanSource.endsWith('.d') || cleanSource.endsWith('.d.ts')) {
 45→        return `\0dts-stub:${cleanSource}`;
 46→      }
 47→      // Check if a .d.ts file would be resolved (e.g., './type.icon' → 'type.icon.d.ts')
 48→      if (
 49→        cleanImporter.includes('node_modules/@semparar/') &&
 50→        !cleanSource.startsWith('\0') &&
 51→        (cleanSource.startsWith('.') || cleanSource.startsWith('/'))
 52→      ) {
 53→        const dir = path.dirname(cleanImporter);
 54→        const candidate = path.resolve(dir, cleanSource);
 55→        const dtsCandidate = candidate + '.d.ts';
 56→        try {
 57→          require('fs').accessSync(dtsCandidate);
 58→          return `\0dts-stub:${dtsCandidate}`;
 59→        } catch {
 60→          // not a .d.ts, let Vite handle it normally
 61→        }
 62→      }
 63→    },
 64→    load(id) {
 65→      if (id.startsWith('\0dts-stub:')) {
 66→        return 'export default {}';
 67→      }
 68→    },
 69→  };
 70→}
 71→
 72→function cjsToEsmPlugin(): PluginOption {
 73→  return {
 74→    name: 'storybook:cjs-to-esm',
 75→    enforce: 'pre',
 76→    transform(code, id) {
 77→      const cleanId = id.replace(/\?.*$/, '');
 78→      if (
 79→        !(/\.js$/.test(cleanId) && code.includes('module.exports')) ||
 80→        !CJS_IN_ESM_PACKAGES.some(pkg => cleanId.includes(pkg))
 81→      ) {
 82→        return;
 83→      }
 84→
 85→      const objMatch = code.match(/module\.exports\s*=\s*\{([^}]+)\}/);
 86→      if (objMatch) {
 87→        const isIdentifier = /^[a-zA-Z_$][a-zA-Z0-9_$]*$/;
 88→        const entries = objMatch[1]
 89→          .split(',')
 90→          .map(e => e.trim())
 91→          .filter(Boolean)
 92→          .filter(e => {
 93→            const parts = e.split(':').map(p => p.trim());
 94→            return parts.every(p => isIdentifier.test(p));
 95→          })
 96→          .map(e => {
 97→            const parts = e.split(':').map(p => p.trim());
 98→            if (parts.length === 2 && parts[0] !== parts[1]) {
 99→              return `export { ${parts[1]} as ${parts[0]} };`;
100→            }
101→            return `export { ${parts[0]} };`;
102→          });
103→        const exportsBlock = entries.join('\n');
104→        return code
105→          .replace(/["']use strict["'];?\s*/, '')
106→          .replace(/module\.exports\s*=\s*\{[^}]+\};?/, exportsBlock);
107→      }
108→
109→      const simpleMatch = code.match(
110→        /module\.exports\s*=\s*([a-zA-Z_$][a-zA-Z0-9_$]*|null|undefined|\d+|'[^']*'|"[^"]*");?/,
111→      );
112→      if (simpleMatch) {
113→        const value = simpleMatch[1];
114→        const basename = cleanId
115→          .replace(/^.*\//, '')
116→          .replace(/\.(web|native)?\.js$/, '');
117→        const namedExport =
118→          basename && /^[a-zA-Z_$]/.test(basename)
119→            ? `export const ${basename} = ${value};\n`
120→            : '';
121→        return code
122→          .replace(/["']use strict["'];?\s*/, '')
123→          .replace(
124→            simpleMatch[0],
125→            `${namedExport}export default ${value};`,
126→          );
127→      }
128→    },
129→  };
130→}
131→
132→const config: StorybookConfig = {
133→  stories: ['../src/**/*.stories.@(ts|tsx)'],
134→
135→  framework: {
136→    name: '@storybook/react-native-web-vite',
137→    options: {
138→      modulesToTranspile: [
139→        'react-native',
140→        'react-native-reanimated',
141→        'react-native-safe-area-context',
142→        'react-native-gesture-handler',
143→        'react-native-icomoon',
144→        'react-native-flip-card',
145→        'react-native-linear-gradient',
146→        'react-native-status-bar-height',
147→        'react-native-svg',
148→        'react-native-svg-charts',
149→        '@semparar/design-system-app',
150→      ],
151→    },
152→  },
153→
154→  addons: ['@storybook/addon-essentials'],
155→
156→  viteFinal: async config => {
157→    config.plugins = config.plugins || [];
158→    config.plugins.push(jsxInJsPlugin());
159→    config.plugins.push(cjsToEsmPlugin());
160→
161→    config.optimizeDeps = config.optimizeDeps || {};
162→    config.optimizeDeps.include = [
163→      ...(config.optimizeDeps.include || []),
164→      'styled-components',
165→      'styled-components/native',
166→      'card-validator',
167→      'credit-card-type',
168→      'lodash',
169→      'xdate',
170→      'invariant',
171→      'fbjs',
172→      'hoist-non-react-statics',
173→      'prop-types',
174→      'object-assign',
175→      'shallowequal',
176→      'moment',
177→    ];
178→
179→    config.resolve = config.resolve || {};
180→    config.resolve.alias = {
181→      ...(config.resolve.alias || {}),
182→      '~': path.resolve(__dirname, '../src'),
183→      '~/store': path.resolve(__dirname, 'mocks/store.ts'),
184→      'postcss': path.resolve(__dirname, '../node_modules/postcss/lib/postcss.mjs'),
185→      'react-native-linear-gradient': path.resolve(
186→        __dirname,
187→        'mocks/react-native-linear-gradient.tsx',
188→      ),
189→      'react-native-modalize': path.resolve(
190→        __dirname,
191→        'mocks/react-native-modalize.tsx',
192→      ),
193→      'react-native-skeleton-placeholder': path.resolve(
194→        __dirname,
195→        'mocks/react-native-skeleton-placeholder.tsx',
196→      ),
197→      '@react-native-community/slider': path.resolve(
198→        __dirname,
199→        'mocks/react-native-community-slider.tsx',
200→      ),
201→      'lottie-react-native': path.resolve(
202→        __dirname,
203→        'mocks/lottie-react-native.tsx',
204→      ),
205→      'react-native-video': path.resolve(
206→        __dirname,
207→        'mocks/react-native-video.tsx',
208→      ),
209→      '@react-native/assets-registry/registry': path.resolve(
210→        __dirname,
211→        'mocks/react-native-assets-registry.tsx',
212→      ),
213→      'deprecated-react-native-prop-types': path.resolve(
214→        __dirname,
215→        'mocks/deprecated-react-native-prop-types.tsx',
216→      ),
217→    };
218→    return config;
219→  },
220→};
221→
222→export default config;
